const psychologyAnalyzer = {
  name: "psychology_analyzer",
  description: "Análise avançada de perfil psicológico DISC baseada em padrões de comunicação",

  async execute(messageContent, conversationContext = {}) {
    try {
      const message = messageContent.toLowerCase();

      // Palavras-chave por perfil DISC
      const discKeywords = {
        dominant: {
          keywords: [
