          ],
          phrases: [
            'que legal', 'adorei', 'fantástico', 'incrível', 'todo mundo',
            'vamos fazer juntos', 'que oportunidade', 'visão de futuro'
          ],
          communication_style: "Entusiasmado, persuasivo, sociável",
          decision_making: "Intuitivo, baseado em pessoas",
          motivation: "Reconhecimento, interação social, inspiração"
        },

        steady: {
          keywords: [
            'estabilidade', 'segurança', 'equipe', 'colaboração', 'harmonia',
            'processo', 'procedimento', 'tradição', 'confiança', 'apoio',
            'cooperação', 'ajuda', 'família', 'relacionamento', 'parceria'
          ],
          phrases: [
            'vamos com calma', 'preciso pensar', 'e a equipe', 'todos concordam',
            'passo a passo', 'sempre fizemos assim', 'prefiro garantir'
          ],
          communication_style: "Calmo, cooperativo, leal",
          decision_making: "Cauteloso, consulta outros",
          motivation: "Estabilidade, trabalho em equipe, harmonia"
        },

        conscientious: {
          keywords: [
            'dados', 'números', 'estudos', 'evidências', 'comprovado', 'estatística',
            'análise', 'detalhes', 'precisão', 'qualidade', 'padrão', 'método',
            'sistema', 'organização', 'planejamento', 'documentação'
          ],
          phrases: [
            'preciso ver os dados', 'qual a evidência', 'como funciona exatamente',
            'preciso analisar', 'qual o processo', 'documentação completa'
          ],
          communication_style: "Analítico, detalhista, factual",
          decision_making: "Baseado em dados, meticuloso",
          motivation: "Precisão, qualidade, conhecimento"
        }
      };

      // Análise de intensidade emocional
      const emotionalIntensity = {
        high: ['!!', 'muito', 'super', 'extremamente', 'urgente', 'crítico'],
        medium: ['interessante', 'legal', 'bacana', 'bom', 'ótimo'],
        low: ['talvez', 'pode ser', 'vou pensar', 'depois vejo']
      };

      // Indicadores de autoridade/decisão
      const authorityIndicators = {
        high: ['decidir', 'aprovar', 'autorizar', 'sou responsável', 'minha empresa'],
        medium: ['vou consultar', 'preciso ver com', 'nossa equipe'],
        low: ['não posso decidir', 'não sou eu quem', 'preciso pedir permissão']
      };

      // Calculando scores
      const scores = {};
      let totalMatches = 0;

      for (const [profile, data] of Object.entries(discKeywords)) {
        let score = 0;

        // Contagem de palavras-chave
        data.keywords.forEach(keyword => {
          if (message.includes(keyword)) {
            score += 2;
            totalMatches += 2;
          }
        });

        // Contagem de frases
        data.phrases.forEach(phrase => {
          if (message.includes(phrase)) {
            score += 3;
            totalMatches += 3;
          }
        });

        scores[profile] = score;
      }

      // Normalizando scores (percentual)
      const normalizedScores = {};
      for (const [profile, score] of Object.entries(scores)) {
        normalizedScores[profile] = totalMatches > 0 ? Math.round((score / totalMatches) * 100) : 25;
      }

      // Determinando perfil predominante
      const predominantProfile = Object.keys(normalizedScores).reduce((a, b) => 
        normalizedScores[a] > normalizedScores[b] ? a : b
      );

      // Análise de intensidade emocional
      let emotionalLevel = 'medium';
      if (emotionalIntensity.high.some(word => message.includes(word))) {
        emotionalLevel = 'high';
      } else if (emotionalIntensity.low.some(word => message.includes(word))) {
        emotionalLevel = 'low';
      }

      // Análise de autoridade
      let authorityLevel = 'medium';
      if (authorityIndicators.high.some(phrase => message.includes(phrase))) {
        authorityLevel = 'high';
      } else if (authorityIndicators.low.some(phrase => message.includes(phrase))) {
        authorityLevel = 'low';
      }

      // Estratégias específicas por perfil
      const strategies = {
        dominant: {
          communication_approach: "Direta, focada em resultados e ROI",
          persuasion_strategy: "Impacto competitivo, economia de tempo, controle",
          offer_timing: "Imediato, com senso de urgência",
          key_phrases: ["resultado imediato", "vantagem competitiva", "economia comprovada"],
          avoid: ["muitos detalhes técnicos", "processo longo", "decisão coletiva"]
        },
        influential: {
          communication_approach: "Entusiasmada, focada em inovação e pessoas",
          persuasion_strategy: "Tendências, reconhecimento, networking",
          offer_timing: "No pico do entusiasmo",
          key_phrases: ["inovação revolucionária", "pioneirismo", "destaque no mercado"],
          avoid: ["dados frios", "análise técnica excessiva", "ceticismo"]
        },
        steady: {
          communication_approach: "Consultiva, empática, focada em relacionamento",
          persuasion_strategy: "Casos de sucesso, depoimentos, garantias",
          offer_timing: "Após construir confiança",
          key_phrases: ["outros clientes relatam", "suporte completo", "implementação gradual"],
          avoid: ["pressão", "mudanças drásticas", "decisões apressadas"]
        },
        conscientious: {
          communication_approach: "Técnica, baseada em dados e evidências",
          persuasion_strategy: "ROI detalhado, estudos, comparativos",
          offer_timing: "Após apresentar todas as evidências",
          key_phrases: ["dados comprovam", "análise detalhada", "metodologia testada"],
          avoid: ["promessas vagas", "pressão emocional", "decisões rápidas"]
        }
      };

      // Confiança da análise
      const confidenceLevel = Math.min(95, 60 + (Math.max(...Object.values(normalizedScores)) * 0.35));

      return {
        success: true,
        analysis: {
          predominant_profile: predominantProfile,
          profile_distribution: normalizedScores,
          emotional_intensity: emotionalLevel,
          authority_level: authorityLevel,
          confidence_level: Math.round(confidenceLevel),

          detailed_profile: {
            name: predominantProfile.toUpperCase(),
            description: discKeywords[predominantProfile].communication_style,
            decision_making: discKeywords[predominantProfile].decision_making,
            motivation: discKeywords[predominantProfile].motivation
          },

          recommended_strategy: strategies[predominantProfile],

          behavioral_indicators: {
            communication_pattern: discKeywords[predominantProfile].communication_style,
            decision_speed: authorityLevel === 'high' ? 'Rápido' : authorityLevel === 'medium' ? 'Moderado' : 'Lento',
            risk_tolerance: predominantProfile === 'dominant' ? 'Alto' : predominantProfile === 'influential' ? 'Médio-Alto' : 'Baixo',
            detail_preference: predominantProfile === 'conscientious' ? 'Alto' : 'Médio'
          }
        },

        actionable_insights: {
          immediate_approach: strategies[predominantProfile].communication_approach,
          persuasion_elements: strategies[predominantProfile].key_phrases,
          timing_recommendation: strategies[predominantProfile].offer_timing,
          things_to_avoid: strategies[predominantProfile].avoid,

          next_questions: {
            dominant: "Qual seu principal objetivo com essa solução?",
            influential: "Como isso pode destacar sua empresa no mercado?", 
            steady: "Como sua equipe se adaptaria a essa mudança?",
            conscientious: "Que dados você precisa para tomar a decisão?"
          }[predominantProfile]
        },

        generated_at: new Date().toISOString()
      };

    } catch (error) {
      return {
        success: false,
        error: error.message,
        fallback: {
          profile: "mixed",
          approach: "consultiva",
          confidence: 50
        }
      };
    }
  }
};

// Execução da ferramenta
const messageContent = "Preciso de dados concretos sobre ROI antes de decidir. Qual a evidência de que funciona?";
const result = await psychologyAnalyzer.execute(messageContent);
return [{ json: result }];

// Tool: ROI Calculator - CORRIGIDO para n8n
const companyProfile = {
  company_type: $json.query?.includes('construtora') ? 'construtora' : 
               $json.query?.includes('corretor') ? 'corretor_autonomo' : 'imobiliaria',
  company_size: $json.query?.includes('grande') ? 'grande' :
               $json.query?.includes('pequena') ? 'pequena' : 'media'
};

// Benchmarks por segmento
const segmentBenchmarks = {
  imobiliaria: {
    pequena: { leads_month: 50, avg_ticket: 1800, conversion: 0.038, team_size: 3 },
    media: { leads_month: 150, avg_ticket: 2340, conversion: 0.042, team_size: 8 },
    grande: { leads_month: 400, avg_ticket: 3200, conversion: 0.055, team_size: 25 }
  },
  construtora: {
    pequena: { leads_month: 30, avg_ticket: 12000, conversion: 0.025, team_size: 5 },
    media: { leads_month: 80, avg_ticket: 18500, conversion: 0.032, team_size: 15 },
    grande: { leads_month: 200, avg_ticket: 35000, conversion: 0.048, team_size: 50 }
  },
  corretor_autonomo: {
    pequena: { leads_month: 25, avg_ticket: 1500, conversion: 0.035, team_size: 1 },
    media: { leads_month: 60, avg_ticket: 2200, conversion: 0.040, team_size: 1 },
    grande: { leads_month: 120, avg_ticket: 3500, conversion: 0.050, team_size: 1 }
  }
};

const segment = companyProfile.company_type;
const size = companyProfile.company_size;
const benchmark = segmentBenchmarks[segment]?.[size] || segmentBenchmarks.imobiliaria.media;

// Situação atual
const current = {
  leads_month: benchmark.leads_month,
  avg_ticket: benchmark.avg_ticket,
  conversion_rate: benchmark.conversion,
  team_size: benchmark.team_size
};

const currentRevenue = current.leads_month * current.conversion_rate * current.avg_ticket;
const leadsLost = Math.floor(current.leads_month * 0.73);
const revenueLost = leadsLost * current.conversion_rate * current.avg_ticket;

// Projeções com SDR IA
const newConversionRate = current.conversion_rate * 3.52; // +252% melhoria
const newRevenue = current.leads_month * newConversionRate * current.avg_ticket;
const additionalRevenue = newRevenue - currentRevenue;
const annualAdditionalRevenue = additionalRevenue * 12;
const investmentRequired = 1890 * 12; // Custo anual SDR IA
const roiPercentage = Math.round((annualAdditionalRevenue / investmentRequired) * 100);
const paybackMonths = Math.round((investmentRequired / additionalRevenue) * 10) / 10;

// Retorna STRING formatada para o n8n
const result = `ANÁLISE ROI PERSONALIZADA:

SITUAÇÃO ATUAL:
- Empresa: ${segment} ${size}
- Leads/mês: ${current.leads_month}
- Conversão atual: ${(current.conversion_rate * 100).toFixed(1)}%
- Receita mensal: R$ ${currentRevenue.toLocaleString('pt-BR')}
- Leads perdidos: ${leadsLost}/mês
- Receita perdida: R$ ${revenueLost.toLocaleString('pt-BR')}/mês

PROJEÇÕES COM SDR IA:
- Nova conversão: ${(newConversionRate * 100).toFixed(1)}%
- Melhoria: +${Math.round(((newConversionRate / current.conversion_rate) - 1) * 100)}%
- Nova receita mensal: R$ ${newRevenue.toLocaleString('pt-BR')}
- Receita adicional: R$ ${additionalRevenue.toLocaleString('pt-BR')}/mês

ANÁLISE FINANCEIRA:
- ROI anual: ${roiPercentage}%
- Payback: ${paybackMonths} meses
- Receita adicional anual: R$ ${annualAdditionalRevenue.toLocaleString('pt-BR')}
- Investimento: R$ ${investmentRequired.toLocaleString('pt-BR')}/ano

CONFIANÇA: 94% (baseado em 500+ imobiliárias)`;

return result;

